values
  ('0b2cf618-5b71-4f0c-9308-f7d651a4d111', 'Где находится Эйфелева башня?', 'Ищи столицу Франции.', 'landmark', 48.85837, 2.294481, 'Europe', 'easy', 'iconic-landmarks', 'Эйфелева башня была построена к Всемирной выставке 1889 года.', null, true),
  ('4e3a538c-93a2-4415-bcca-d589447f7b80', 'Где находится Статуя Свободы?', 'Она встречает корабли у Нью-Йорка.', 'landmark', 40.689249, -74.0445, 'North America', 'easy', 'iconic-landmarks', 'Статуя Свободы была подарена США Францией.', null, true),
  ('917d31f9-bd8a-41ec-a66a-70632c7f0e91', 'Где находится Сиднейский оперный театр?', 'Это один из символов Австралии.', 'landmark', -33.856784, 151.215297, 'Oceania', 'medium', 'iconic-landmarks', 'Здание оперы известно своими силуэтами в форме парусов.', null, true),
  ('cfc5c85d-73d4-4bca-a185-cff5a58e32f2', 'Где находится Христос-Искупитель?', 'Это символ Рио-де-Жанейро.', 'landmark', -22.951916, -43.210487, 'South America', 'medium', 'iconic-landmarks', 'Статуя стоит на вершине горы Корковаду и видна почти из любой части города.', null, true),
  ('b7ed89f7-8b55-4e61-a195-9e6a6f6514a1', 'Где находится гора Фудзи?', 'Это Япония.', 'landmark', 35.360638, 138.727356, 'Asia', 'medium', 'iconic-landmarks', 'Фудзи — самая высокая гора Японии и важный культурный символ страны.', null, true),
  ('c01e40ca-7f4e-4561-a5f2-b9500c34b13a', 'Где находится Золотой мост в Сан-Франциско?', 'Это известный красный мост в Калифорнии.', 'landmark', 37.8199, -122.4783, 'North America', 'easy', 'iconic-landmarks', 'Golden Gate Bridge при открытии был самым длинным подвесным мостом в мире.', null, true),
  ('11d5a6b7-c801-4b8c-9d0e-1f2a3b4c5d60', 'Где находится Биг-Бен?', 'Ориентируйся на Лондон.', 'landmark', 51.5007, -0.1246, 'Europe', 'easy', 'iconic-landmarks', 'Название Биг-Бен изначально относилось к главному колоколу, а не ко всей башне.', null, true),
  ('22e6b7c8-d912-4c9d-8e1f-2a3b4c5d6e71', 'Где находится Колизей?', 'Ищи столицу Италии.', 'landmark', 41.8902, 12.4922, 'Europe', 'easy', 'iconic-landmarks', 'Колизей был крупнейшим амфитеатром Древнего Рима и вмещал десятки тысяч зрителей.', null, true),
  ('33f7c8d9-e023-4dae-9f20-3b4c5d6e7f82', 'Где находится Бурдж-Халифа?', 'Это небоскрёб в Объединённых Арабских Эмиратах.', 'landmark', 25.1972, 55.2744, 'Asia', 'medium', 'iconic-landmarks', 'Бурдж-Халифа остаётся самым высоким зданием в мире.', null, true),
  ('44a8d9e0-f134-4ebf-8a31-4c5d6e7f8093', 'Где находится CN Tower?', 'Это башня в крупнейшем городе Канады.', 'landmark', 43.6426, -79.3871, 'North America', 'medium', 'iconic-landmarks', 'CN Tower долгое время была самым высоким отдельно стоящим сооружением на планете.', null, true),
  ('55b9e0f1-a245-4fc0-9b42-5d6e7f8091a4', 'Где находится Саграда Фамилия?', 'Ищи Барселону.', 'landmark', 41.4036, 2.1744, 'Europe', 'medium', 'iconic-landmarks', 'Саграда Фамилия строится дольше века и остаётся главным архитектурным символом Барселоны.', null, true),
  ('66ca0f12-b356-40d1-8c53-6e7f8091a2b5', 'Где находится Space Needle?', 'Ориентируйся на Сиэтл.', 'landmark', 47.6205, -122.3493, 'North America', 'medium', 'iconic-landmarks', 'Space Needle построили к Всемирной выставке 1962 года и сделали символом Сиэтла.', null, true),

  ('880a1229-dddb-4ce6-9b76-6f2e8f44f76b', 'Где находится Тадж-Махал?', 'Он находится в Индии.', 'landmark', 27.175144, 78.042142, 'Asia', 'medium', 'world-wonders', 'Тадж-Махал был построен как мавзолей по приказу шаха Джахана.', null, true),
  ('5e95e3df-eef3-4306-a8ad-8dd0d32fbf9d', 'Где находятся пирамиды Гизы?', 'Они находятся рядом с Каиром.', 'landmark', 29.979235, 31.134202, 'Africa', 'easy', 'world-wonders', 'Пирамида Хеопса — единственное сохранившееся чудо света из античного списка.', null, true),
  ('930f9a4d-9d3a-4649-bd8a-cf483d0f0df3', 'Где находится Мачу-Пикчу?', 'Высоко в Андах.', 'landmark', -13.163141, -72.544963, 'South America', 'hard', 'world-wonders', 'Мачу-Пикчу был заново открыт для внешнего мира в начале XX века.', null, true),
  ('ad7a2a03-b7a2-4270-9992-a62a339eb333', 'Где находится Ангкор-Ват?', 'Ищи Камбоджу.', 'landmark', 13.4125, 103.866667, 'Asia', 'hard', 'world-wonders', 'Ангкор-Ват сначала был индуистским храмом, а потом стал буддийским.', null, true),
  ('0d9e2d6a-6c49-4046-aef3-b19d18b0ba01', 'Где находится Петра?', 'Ищи Иорданию.', 'landmark', 30.3285, 35.4444, 'Asia', 'hard', 'world-wonders', 'Петра знаменита фасадами, высеченными прямо в скалах розового цвета.', null, true),
  ('a0e4a3fe-1d36-4914-9ca3-c72177cf05dd', 'Где находится Чичен-Ица?', 'Древний памятник на полуострове Юкатан.', 'landmark', 20.6843, -88.5678, 'North America', 'hard', 'world-wonders', 'Чичен-Ица была одним из крупнейших центров цивилизации майя.', null, true),
  ('77db1023-c467-41e2-9d64-7f8091a2b3c6', 'Где находится Великая китайская стена?', 'Ориентируйся на север Китая.', 'landmark', 40.4319, 116.5704, 'Asia', 'medium', 'world-wonders', 'Великая китайская стена состоит из множества участков, построенных в разные эпохи.', null, true),
  ('88ec2134-d578-42f3-8e75-8091a2b3c4d7', 'Где находится Стоунхендж?', 'Древний каменный круг на юге Англии.', 'landmark', 51.1789, -1.8262, 'Europe', 'hard', 'world-wonders', 'Точное назначение Стоунхенджа до сих пор остаётся предметом споров археологов.', null, true),
  ('99fd3245-e689-4304-9f86-91a2b3c4d5e8', 'Где находится Запретный город?', 'Исторический центр Пекина.', 'landmark', 39.9163, 116.3972, 'Asia', 'medium', 'world-wonders', 'Запретный город был императорской резиденцией Китая почти пять столетий.', null, true),
  ('aa0e4356-f79a-4415-8a97-a2b3c4d5e6f9', 'Где находятся статуи моаи на острове Пасхи?', 'Ищи удалённый остров в юго-восточной части Тихого океана.', 'landmark', -27.1212, -109.3664, 'Oceania', 'hard', 'world-wonders', 'Моаи вырезали жители Рапа-Нуи из вулканического туфа и устанавливали по всему острову.', null, true),
  ('bb1f5467-a8ab-4526-9ba8-b3c4d5e6f70a', 'Где находится Килиманджаро?', 'Самая высокая вершина Африки.', 'landmark', -3.0674, 37.3556, 'Africa', 'medium', 'world-wonders', 'Килиманджаро — самый высокий отдельно стоящий вулкан на планете.', null, true),
  ('cc206578-b9bc-4637-8cb9-c4d5e6f7081b', 'Где находится Улуру?', 'Монолит в центре Австралии.', 'landmark', -25.3444, 131.0369, 'Oceania', 'medium', 'world-wonders', 'Улуру имеет огромное культурное значение для народа анангу и меняет оттенок в разное время суток.', null, true),

  ('7af5178a-5d8a-49f5-ae88-f17bac9f0a92', 'Где находится Рейкьявик?', 'Столица островного государства в Северной Атлантике.', 'city', 64.1466, -21.9426, 'Europe', 'medium', 'capitals', 'Рейкьявик считается самой северной столицей независимого государства.', null, true),
  ('2aa713f1-b8aa-4b95-a5f3-7f8ce6041df5', 'Где находится Кейптаун?', 'Город у подножия Столовой горы.', 'city', -33.9249, 18.4241, 'Africa', 'medium', 'capitals', 'Кейптаун часто входит в рейтинги самых живописных городов мира.', null, true),
  ('c8f6a7f2-1ce0-4ff0-8556-3f7131f39a11', 'Где находится Париж?', 'Это столица Франции.', 'city', 48.8566, 2.3522, 'Europe', 'easy', 'capitals', 'Париж часто называют городом света.', null, true),
  ('fa93d98c-4e58-4fce-b91d-324f4c5d2df1', 'Где находится Токио?', 'Это столица Японии.', 'city', 35.6762, 139.6503, 'Asia', 'medium', 'capitals', 'Токио — крупнейшая по населению агломерация в мире.', null, true),
  ('5bf7df60-2c77-4290-9b5f-3c1ffab37d52', 'Где находится Каир?', 'Столица Египта на берегах Нила.', 'city', 30.0444, 31.2357, 'Africa', 'medium', 'capitals', 'Каир — один из крупнейших городов Африки и Ближнего Востока.', null, true),
  ('ebdb2832-a70b-4282-bf5b-6799895adf31', 'Где находится Оттава?', 'Это столица Канады.', 'city', 45.4215, -75.6972, 'North America', 'medium', 'capitals', 'Оттава расположена на границе провинций Онтарио и Квебек.', null, true),
  ('9f2de8f7-dc7c-42fd-87d3-3b009f97989f', 'Где находится Бразилиа?', 'Это столица Бразилии, построенная почти с нуля.', 'city', -15.7939, -47.8828, 'South America', 'medium', 'capitals', 'Бразилиа известна модернистской архитектурой и необычной планировкой.', null, true),
  ('dd317689-cacd-4748-9dca-d5e6f708192c', 'Где находится Вашингтон?', 'Столица США расположена между Мэрилендом и Вирджинией.', 'city', 38.9072, -77.0369, 'North America', 'easy', 'capitals', 'Вашингтон образует отдельный федеральный округ и не входит ни в один штат США.', null, true),
  ('ee42879a-dbde-4859-8edb-e6f708192a3d', 'Где находится Рим?', 'Это столица Италии.', 'city', 41.9028, 12.4964, 'Europe', 'easy', 'capitals', 'Рим называют вечным городом, а внутри него находится государство Ватикан.', null, true),
  ('ff5398ab-ecef-496a-9fec-f708192a3b4e', 'Где находится Мадрид?', 'Это столица Испании.', 'city', 40.4168, -3.7038, 'Europe', 'easy', 'capitals', 'Мадрид расположен почти в самом центре Пиренейского полуострова.', null, true),
  ('0a64a9bc-fd01-4a7b-8afd-08192a3b4c5f', 'Где находится Сеул?', 'Столица Южной Кореи.', 'city', 37.5665, 126.9780, 'Asia', 'medium', 'capitals', 'Сеул — один из крупнейших мегаполисов и технологических центров Азии.', null, true),
  ('1b75bacd-0e12-4b8c-9b0e-192a3b4c5d60', 'Где находится Веллингтон?', 'Столица Новой Зеландии на юге Северного острова.', 'city', -41.2866, 174.7756, 'Oceania', 'medium', 'capitals', 'Веллингтон часто называют самой ветреной столицей мира.', null, true),
  ('2c86cbde-1f23-4c9d-8c1f-2a3b4c5d6e71', 'Где находится Буэнос-Айрес?', 'Столица Аргентины у устья Ла-Платы.', 'city', -34.6037, -58.3816, 'South America', 'medium', 'capitals', 'Буэнос-Айрес считается родиной современного танго и одним из главных культурных центров Южной Америки.', null, true)
on conflict (id) do update
